sql:
SELECT MAX(rating) AS highest_rating
FROM course_ratings
WHERE course_id = 0;

SELECT DISTINCT user_id
  FROM subscription_history
  WHERE change_type = 'upgrade';

SELECT subscription_name
FROM subscriptions
WHERE subscription_id = 0;
